@Test
    public void testMaxDenominatorConstraint() {
        // Test with small maxDenominator to ensure previous convergent is used
        try {
            Fraction f = new Fraction(Math.PI, 0.00001, 10, 100);
            Assert.assertTrue("Denominator should be <= 10", f.getDenominator() <= 10);
            Assert.assertTrue("Should approximate PI reasonably", 
                Math.abs(f.doubleValue() - Math.PI) < 0.01);
        } catch (Exception e) {
            Assert.fail("Should not throw exception: " + e.getMessage());
        }
    }

@Test
    public void testEpsilonConvergence() {
        // Test that epsilon constraint is respected
        try {
            Fraction f = new Fraction(0.333333, 0.001, 1000, 100);
            Assert.assertTrue("Should converge within epsilon", 
                Math.abs(f.doubleValue() - 0.333333) <= 0.001);
        } catch (Exception e) {
            Assert.fail("Should not throw exception: " + e.getMessage());
        }
    }

@Test
    public void testSmallPositiveValue() {
        // Test small positive value that might cause issues
        try {
            Fraction f = new Fraction(0.00001, 1.0e-10, 10000, 100);
            Assert.assertTrue("Should handle small positive value", f.getNumerator() > 0);
            Assert.assertTrue("Denominator should be reasonable", f.getDenominator() <= 10000);
        } catch (Exception e) {
            Assert.fail("Should not throw exception: " + e.getMessage());
        }
    }
